def _quantize_to_error_threshold(self, colors, method, kmeans, error_threshold):
    from . import ImageChops

    def mean_square_error(im1, im2):
        diff = ImageChops.difference(im1, im2)
        h = diff.histogram()
        bands = len(h) // 256
        total = 0
        count = 0
        for band in range(bands):
            band_hist = h[band * 256 : (band + 1) * 256]
            for value, n in enumerate(band_hist):
                total += (value**2) * n
                count += n
        return total / count

    lo, hi = 1, colors
    best = None
    while lo <= hi:
        mid = (lo + hi) // 2
        candidate = self._new(self.im.quantize(mid, method, kmeans))
        converted = candidate.convert(self.mode)
        if mean_square_error(self, converted) <= error_threshold:
            best = candidate
            hi = mid - 1
        else:
            lo = mid + 1

    if best is not None:
        return best
    return self._new(self.im.quantize(colors, method, kmeans))

